INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('customs-f19eb2bd-moex-00037', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「一面走動，跟緊外婆怕跟丟，一面忙吃。冰在糖漿裡瞬間就化水，不時 吮一口融冰，才不會走著走著晃出來。且記得把冰遞回給外婆，她也吃上 幾口。這種含糖時刻是祖孫倆放風的樂趣，彼此掩護是為溺愛。兒時的米 苔目時光，都與我外婆一道。長大生出了自己的偏好，多年不吃，兼排斥 一切粗麵。麵吃細麵，吃粉就選米粉米線。米苔目這白胖的粉食，跟粗米 粉被我歸成同一路，覺得味道寡淡。現在回頭去找米苔目，懷念的仍不是 味道，而是童年。」 根據上文，下列選項最符合文意的是：', '["米苔目冰能緩緩化水，吮飲融冰是作者童年時的一大樂趣", "外婆和幼年作者常被禁止吃糖，因此會一起偷吃米苔目冰", "作者雖不愛吃粗麵和粗米粉，仍愛品嚐滋味清淡的米苔目", "作者長大後吃米苔目，除了懷念味道，也是紀念童年時光"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00038', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「節約不盡然是苦行僧式的刻苦。我的意思是說，刻苦的概念必然包含抗 拒豐饒的誘惑：拒絕太多食物、太多富足、太多財物、太多享樂。刻苦的 人譴責享樂，認為它容易導致放縱。因此必須節制，減量，排除。刻苦的 概念有一大成分是嚴峻，一種對樂趣的輕視乃至恐懼。刻苦是拒絕自我解 放，禁止讓自己感受程度太深，以免無法節制。節制則是發現簡單能夠帶 來滿足，發現人可以幾乎一無所有——只有一杯清水，一顆水果，一陣涼 風——卻感到無比幸福。」 根據上文，下列選項何者正確？', '["追求刻苦的人生，可拒絕豐饒的誘惑，因而能享受富足", "刻苦的目的是為了讓生活更為簡單，因此完全拒絕生活的享樂", "「節約」是發現簡單能帶來幸福，而不是刻意讓自己感到匱乏與痛苦", "我們應當學習苦行僧式的生活態度，才能讓生活變得更為簡約而自由"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00039', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「有首曲子，希望用在我的葬禮上。這是第一首讓我大哭的音樂——貝多 芬的『皇帝』鋼琴協奏曲。標題被安上『皇帝』，是因為它誇張的特色。 曲子首尾兩樂章，音符充耳，如煙火散落；中間的第二樂章，極美，平靜， 讓人屏息。我那時比較年輕，不大能駕馭，現在我已長大，音樂能做什麼， 全展現其中。」 根據上文，下列選項最符合文意的是：', '["鋼琴家希望葬禮隆重，樂曲具莊嚴堂皇之風，以切合他的身分", "鋼琴家自認要到晚年，才能駕馭貝多芬炫麗的「皇帝」協奏曲", "貝多芬失聰後作的「皇帝」協奏曲，高低起伏，令鋼琴家仰慕", "「皇帝」協奏曲兼具燦爛、平靜曲風，適合詮釋鋼琴家的一生"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00040', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「善良的人無法喜愛一件新的作品，但當這作品問世二十年後卻又真誠地 喜愛它，這是常有的事。新生命的香味太濃了，他們虛弱的頭腦承受不了， 香氣會隨著時間的流逝而漸漸揮發掉。藝術品只有在覆滿陳年積垢時才會 被他們理解。」 根據上文，下列選項何者最符合文意？', '["人類大多是善變無常", "只有強者才善於創造", "創作者難免承受孤獨", "善良無助於評價優劣"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00041', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「雖然組織胺的主要任務是保護身體的安全，但是這些保鑣有時對很多東 西都視為威脅。例如飄在空氣中的花粉，或家中寵物的毛髮、皮屑，組織 胺都想要把它們擋在身體之外，而下達排除的指令。這些會引發身體組織 胺大量分泌的外界物質稱為『過敏原』，這些物質引發的身體反應稱為『過 敏』。」 根據上文，下列選項何者與上文所言相抵觸？', '["組織胺就像體內保鑣多多益善", "過敏原會引發身體大量分泌組織胺", "花粉或寵物的毛髮、皮屑都有可能是過敏原", "過敏是對自然環境中的過敏原產生反應的現象"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00042', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '村上春樹曾說過：「不管多大年紀都無所謂，無非就是個恰到好處的人罷 了。」不必非得去裝年輕，也不必去感慨歲月滄桑，「花開花落自有時」， 追隨大自然的規律，一切都剛剛好！ 根據上文，下列選項最符合文意的是：', '["健康長壽是老年人最大的幸福", "努力改變自己，讓自己活得更精彩", "不管什麼年齡，接納自己，好壞都自有安排", "年輕時就該為老年計劃，才不至於老大徒傷悲"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00043', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「電車通過櫻花隧道之際，也讓人湧起一股如夢似幻的感受，難道這輛穿 越花海的電車，最終會開往夢幻天堂？京都的美經常給人一種不真實感， 美到讓人無法呼吸，讓人無法忍受，最後不得不像《金閣寺》裡的小和尚， 忍不住一把火將金閣寺燒掉！日本的櫻花美學就是要去擁抱、珍惜短暫的 極致美感，美的極致之後，就不在乎毀滅或死亡了！」 根據上文，下列選項何者最符合文意？', '["櫻花盛開有如熊熊火焰，似乎要將一切景物吞沒殆盡", "櫻花盛開時的美感極為短暫虛幻，所以不能沉迷其中", "人們若曾經領略如櫻花盛放的美好片刻，就了無遺憾", "小和尚在櫻花盛開之時縱火焚寺，是殉美的極致表現"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00044', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「處理報導內容的重要區塊時，記者要像嚮導一樣。他提出門外漢都會做 的謹慎結論，但也必須列出一些證據來佐證那些結論。如果沒有證據，文 章會顯得自以為是，空洞不實。不過，在文章的邊緣區塊，記者不再只是 嚮導，他可以利用讀者賦予的代理權，為讀者提供臨場感及人物的實感。」 根據上文，下列選項最符合文意的是：', '["記者報導應該致力突破文章邊界，爭取讀者代理權", "報導以詳細證據輔助結論，並從讀者角度強化感受", "新聞報導通常只會給出常人可知的結論，以免犯錯", "新聞報導追求臨場感與人物實感，反而削減證據力"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00045', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「AI的本質是去取代人的腦力，也就是所謂的專家智慧；而法律的本質， 不純粹是追求價值觀的維護，而更傾向是經濟、政治、科技改變下的產物。 在可預見的未來，AI技術即將衝擊到法律的解釋適用，而當社會進一步受 到 AI 衝擊後，應運而生的將是許多因應 AI 的修法，如 AI 篩選面試者的 機制可能造成的歧視、隱私權問題。」 下列敘述何者正確？', '["AI智慧將會完全取代專家", "AI科技不會衝擊人文法律", "AI的本質是追求絕對價值", "AI執行仍須專家整合思考"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 45, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00046', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-113-34c7f7f6', 'sub-customs-f19eb2bd-01', NULL, 'single_choice', '「聯合國在2022年發布的2023人口報告中就警告，所有國家都需要為人 口老化的現實做好準備。因為社會與經濟的衰老與停滯是大多數富裕國家 與中等收入國家被迫面對的共同難題。生存狀況顯著改善與生育率下降， 已經讓人口老化成為這個時代不可逆轉的全球趨勢，越晚面對人口老化問 題，所要負擔的社會、經濟、財政和衛生成本將越高昂。」 根據上文，關於人口老化的原因，下列推論何者正確？', '["富裕與中等收入國家的政策是造成人口老化的原因", "經濟不斷衰退，造成人口老化，這是目前全球所面臨的難題", "因為衛生成本逐年增加，導致經濟停滯，間接影響國家的生存狀況", "生育率下降與生存狀況的改善，讓人口老化成為全球共同面臨的問題"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:25+00:00", "source_pdf_sha1": "d56e2c7fb363", "answer_pdf_sha1": "6c38fc9e000a", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "161", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
